const QUESTIONS_CISM_C2 = [
  { id:10241, domain:2, level:1, question:"What is the PRIMARY purpose of information risk management?", options:["A Document all threats and vulnerabilities","B Eliminate all risks to information assets","C Align risk levels with business objectives and risk appetite","D Transfer risk to third parties"], correct:2, explanation:"Information risk management aims to align residual risk with the organization's risk appetite and business objectives, not to eliminate all risk, which is neither practical nor cost-effective." },
  { id:10242, domain:2, level:1, question:"Which term describes the potential for a threat to exploit a vulnerability and cause harm?", options:["A Exposure","B Impact","C Likelihood","D Risk"], correct:3, explanation:"Risk is the potential for a threat to exploit a vulnerability resulting in harm to the organization; it combines likelihood and impact." },
  { id:10243, domain:2, level:1, question:"What is 'inherent risk'?", options:["A Risk accepted by senior management","B Risk transferred to a third party","C Risk that exists before any controls are implemented","D Risk remaining after controls are applied"], correct:2, explanation:"Inherent risk is the level of risk that exists in the absence of any controls or mitigation measures." },
  { id:10244, domain:2, level:1, question:"What is 'residual risk'?", options:["A Risk identified during a vulnerability scan","B Risk that cannot be quantified","C Risk eliminated by insurance","D Risk remaining after controls have been applied"], correct:3, explanation:"Residual risk is the risk that remains after risk treatment controls have been implemented and is what management must accept or further address." },
  { id:10245, domain:2, level:1, question:"Which of the following BEST describes risk appetite?", options:["A The difference between inherent and residual risk","B The amount and type of risk an organization is willing to pursue or accept","C The cost of implementing risk controls","D The maximum loss an organization can absorb"], correct:1, explanation:"Risk appetite is the amount and type of risk an organization is willing to accept in pursuit of its objectives, set by senior leadership." },
  { id:10246, domain:2, level:1, question:"Which risk treatment option involves purchasing insurance?", options:["A Risk avoidance","B Risk mitigation","C Risk acceptance","D Risk transfer"], correct:3, explanation:"Risk transfer shifts the financial consequences of a risk to a third party, such as an insurer, without eliminating the underlying risk." },
  { id:10247, domain:2, level:1, question:"In quantitative risk analysis, what does ALE stand for?", options:["A Aggregate Loss Event","B Annualized Likelihood of Exposure","C Asset Liability Estimate","D Annual Loss Expectancy"], correct:3, explanation:"ALE (Annual Loss Expectancy) equals SLE multiplied by ARO and represents the expected yearly loss from a specific risk." },
  { id:10248, domain:2, level:1, question:"What does SLE represent in quantitative risk analysis?", options:["A The monetary loss expected from a single occurrence of a risk event","B The cost of a security control","C The total value of all assets","D The probability that a threat will occur in a year"], correct:0, explanation:"Single Loss Expectancy (SLE) is the expected financial loss each time a specific risk event occurs, calculated as asset value multiplied by exposure factor." },
  { id:10249, domain:2, level:1, question:"What does ARO represent in quantitative risk analysis?", options:["A Asset Recovery Objective","B Automated Risk Override","C Acceptable Risk Outcome","D Annualized Rate of Occurrence"], correct:3, explanation:"ARO (Annualized Rate of Occurrence) is the estimated frequency with which a threat is expected to occur within a one-year period." },
  { id:10250, domain:2, level:1, question:"Which framework is specifically designed for information security risk assessment and is published by NIST?", options:["A FAIR","B ISO 31000","C NIST SP 800-30","D OCTAVE"], correct:2, explanation:"NIST SP 800-30 is the Guide for Conducting Risk Assessments specifically designed for information systems and is published by the National Institute of Standards and Technology." },
  { id:10251, domain:2, level:1, question:"What is a risk register?", options:["A A list of approved security vendors","B A tool for automatically blocking threats","C A document that records identified risks, their attributes, and treatment decisions","D A log of past security incidents"], correct:2, explanation:"A risk register is a centralized repository that records identified risks, their likelihood, impact, owners, and treatment decisions, serving as a key risk management artifact." },
  { id:10252, domain:2, level:1, question:"Which of the four risk treatment options involves discontinuing the activity that creates the risk?", options:["A Risk mitigation","B Risk transfer","C Risk avoidance","D Risk acceptance"], correct:2, explanation:"Risk avoidance means ceasing or not undertaking the activity that introduces the risk, eliminating both the risk and the associated opportunity." },
  { id:10253, domain:2, level:1, question:"What is a Key Risk Indicator (KRI)?", options:["A A forward-looking metric that signals rising risk exposure","B A metric that quantifies the cost of a security breach","C A record of past incidents","D A control effectiveness rating"], correct:0, explanation:"KRIs are forward-looking metrics that provide early warning of increasing risk exposure, enabling proactive management before risk materializes." },
  { id:10254, domain:2, level:1, question:"Who is ultimately accountable for risk acceptance in an organization?", options:["A External auditors","B Senior management or the board","C The CISO","D The IT department"], correct:1, explanation:"Ultimate accountability for risk acceptance rests with senior management or the board, as they set risk appetite and are responsible for organizational outcomes." },
  { id:10255, domain:2, level:1, question:"In risk assessment, what is a 'threat'?", options:["A A documented risk treatment plan","B The financial impact of a security event","C A potential cause of an incident that could harm assets","D A weakness in a system or process"], correct:2, explanation:"A threat is any potential cause of an unwanted incident that could harm an asset or organization; threats exploit vulnerabilities to cause impact." },
  { id:10256, domain:2, level:1, question:"What is the difference between risk tolerance and risk appetite?", options:["A Risk appetite applies only to financial risks","B Risk tolerance is always higher than risk appetite","C They are synonymous terms","D Risk tolerance is the acceptable deviation from risk appetite"], correct:3, explanation:"Risk appetite is the overall level of risk an organization will accept, while risk tolerance is the acceptable variation around that appetite for specific risk categories." },
  { id:10257, domain:2, level:1, question:"Which qualitative risk assessment tool uses a grid to plot likelihood against impact?", options:["A Monte Carlo simulation","B FMEA","C Fault tree analysis","D A risk matrix (heat map)"], correct:3, explanation:"A risk matrix or heat map plots risks by likelihood and impact on a two-dimensional grid, providing a visual prioritization tool for qualitative analysis." },
  { id:10258, domain:2, level:1, question:"What is the Exposure Factor (EF) in quantitative risk analysis?", options:["A The number of vulnerabilities in a system","B The percentage of asset value lost if a risk event occurs","C The annual cost of a security control","D The probability a threat occurs each year"], correct:1, explanation:"Exposure Factor (EF) is the percentage of the asset's value that would be lost if a specific threat were to materialize, used to calculate SLE." },
  { id:10259, domain:2, level:1, question:"Which risk assessment framework focuses on the Factor Analysis of Information Risk?", options:["A FAIR","B ISO 31000","C NIST SP 800-30","D OCTAVE"], correct:0, explanation:"FAIR (Factor Analysis of Information Risk) is a quantitative framework that decomposes risk into measurable factors to produce financial risk estimates." },
  { id:10260, domain:2, level:1, question:"What type of risk assessment relies on numerical values and financial figures?", options:["A Qualitative risk assessment","B Quantitative risk assessment","C Semi-quantitative risk assessment","D Descriptive risk assessment"], correct:1, explanation:"Quantitative risk assessment uses numerical data and financial figures (like ALE, SLE, ARO) to express risk in monetary terms, enabling cost-benefit analysis of controls." },
  { id:10261, domain:2, level:2, question:"A security manager finds that the cost of a control exceeds the ALE of the risk it addresses. What is the MOST appropriate recommendation?", options:["A Transfer the risk to a third party","B Implement the control anyway to ensure compliance","C Escalate to the board for decision","D Accept the risk as the control is not cost-justified"], correct:3, explanation:"When control costs exceed ALE, the control is not economically justified and risk acceptance is the rational choice, unless non-financial factors such as regulatory requirements override cost-benefit logic." },
  { id:10262, domain:2, level:2, question:"During a risk assessment, a newly discovered vulnerability has no known exploits. How should this BEST be categorized?", options:["A Excluded from the risk register until an exploit is found","B Low risk because no exploits currently exist","C High risk because the vulnerability exists","D Risk rated based on both likelihood and potential impact if exploited"], correct:3, explanation:"Even without known exploits, risks should be rated on both likelihood (currently low but not zero) and potential impact, ensuring the vulnerability is monitored appropriately." },
  { id:10263, domain:2, level:2, question:"An organization outsources payroll processing to a third party. Who retains ownership of the associated data risk?", options:["A The payroll software developer","B The third-party vendor","C The organization that outsourced the processing","D The employees whose data is processed"], correct:2, explanation:"Risk ownership remains with the organization regardless of outsourcing; the organization is accountable for data protection even when processing is delegated to a vendor." },
  { id:10264, domain:2, level:2, question:"Which of the following BEST describes the purpose of a Business Impact Analysis (BIA)?", options:["A To determine the financial and operational effects of disruptive events on business processes","B To create a risk register","C To identify all system vulnerabilities","D To assess the security posture of vendors"], correct:0, explanation:"A BIA identifies critical business functions and quantifies the impact (financial, operational, reputational) of disruptions, informing recovery priorities and risk treatment decisions." },
  { id:10265, domain:2, level:2, question:"A risk manager wants to communicate risk levels to the board. Which format is MOST appropriate?", options:["A A risk heat map with business context and treatment options","B Detailed technical vulnerability reports","C Raw logs from the SIEM","D A complete list of all CVEs"], correct:0, explanation:"A risk heat map with business context translates technical risk data into strategic terms that board members can understand, supporting informed risk acceptance decisions." },
  { id:10266, domain:2, level:2, question:"Which OCTAVE phase focuses on identifying organizational risk drivers from a business perspective?", options:["A Phase 1: Build Asset-Based Threat Profiles","B Phase 3: Develop Security Strategy","C Phase 4: Implement Controls","D Phase 2: Identify Infrastructure Vulnerabilities"], correct:0, explanation:"OCTAVE Phase 1 builds asset-based threat profiles by engaging business units to identify critical assets, threats, and security requirements from an organizational perspective." },
  { id:10267, domain:2, level:2, question:"What is the PRIMARY benefit of using a standardized risk assessment framework?", options:["A It guarantees no security incidents will occur","B It reduces the number of identified risks","C It ensures consistency and repeatability in risk evaluations","D It eliminates the need for risk acceptance"], correct:2, explanation:"Standardized frameworks ensure that risk assessments are conducted consistently across the organization, enabling valid comparisons and reproducible results over time." },
  { id:10268, domain:2, level:2, question:"An organization identifies a risk with high inherent risk but low residual risk. What does this indicate?", options:["A Controls are ineffective","B Controls are highly effective at reducing the risk","C The risk has not been properly assessed","D The risk should be avoided"], correct:1, explanation:"A large gap between high inherent risk and low residual risk indicates that implemented controls are effectively reducing the risk to an acceptable level." },
  { id:10269, domain:2, level:2, question:"Which of the following is a PRIMARY characteristic of a risk scenario?", options:["A It lists all system vulnerabilities","B It describes a specific control implementation","C It defines the organization's risk appetite","D It narrates a plausible sequence of threat events and their impacts"], correct:3, explanation:"A risk scenario describes a plausible sequence of events including threat actors, methods, assets affected, and business impact, making abstract risks tangible for assessment." },
  { id:10270, domain:2, level:2, question:"What should trigger an update to the risk register?", options:["A When new threats, vulnerabilities, or significant business changes occur","B When the CISO requests it","C Only after a security incident","D Only at annual review cycles"], correct:0, explanation:"The risk register should be a living document updated whenever new threats emerge, vulnerabilities are discovered, or business changes alter the risk landscape." },
  { id:10271, domain:2, level:2, question:"An organization accepts a risk that exceeds its stated risk tolerance. What is the REQUIRED action?", options:["A Remove the risk from the register","B Immediately implement mitigating controls","C Document the decision with senior management approval","D Transfer the risk to an insurer"], correct:2, explanation:"When accepting a risk that exceeds risk tolerance, formal documentation with appropriate senior management or board approval is required to ensure accountability and governance." },
  { id:10272, domain:2, level:2, question:"Which risk treatment option is MOST appropriate when the cost of mitigation far exceeds the asset value?", options:["A Risk transfer","B Risk acceptance","C Risk mitigation","D Risk avoidance"], correct:1, explanation:"When mitigation costs are disproportionate to the asset value at risk, accepting the risk is economically rational, provided it aligns with risk appetite." },
  { id:10273, domain:2, level:2, question:"What is the PRIMARY purpose of risk monitoring activities?", options:["A To assign blame for security incidents","B To eliminate the need for future risk assessments","C To ensure risks and controls remain aligned with the current threat landscape","D To create new risks"], correct:2, explanation:"Risk monitoring ensures that identified risks, implemented controls, and KRIs remain relevant and effective as threats, vulnerabilities, and business conditions evolve." },
  { id:10274, domain:2, level:2, question:"Which of the following BEST describes 'threat modeling'?", options:["A A structured approach to identifying and prioritizing threats to a system","B Creating a financial model of potential losses","C Performing penetration testing","D Documenting past security incidents"], correct:0, explanation:"Threat modeling is a structured process for identifying, quantifying, and prioritizing potential threats to systems, helping focus security efforts on the most significant risks." },
  { id:10275, domain:2, level:2, question:"What is the MAIN advantage of qualitative risk assessment over quantitative?", options:["A It produces exact financial loss figures","B It is more accurate for decision-making","C It eliminates subjectivity from the process","D It is faster and requires less data, making it practical when precise data is unavailable"], correct:3, explanation:"Qualitative risk assessment is practical when precise data is unavailable, using relative scales that allow for faster assessment, though it introduces more subjectivity than quantitative methods." },
  { id:10276, domain:2, level:2, question:"A vendor contract lacks security requirements. What risk category does this BEST represent?", options:["A Strategic risk","B Third-party/supply chain risk","C Operational risk","D Technical risk"], correct:1, explanation:"Inadequate security requirements in vendor contracts represent third-party or supply chain risk, where the organization's risk exposure extends beyond its direct control." },
  { id:10277, domain:2, level:2, question:"Which of the following is an example of risk avoidance?", options:["A Accepting low-probability risks","B Deciding not to store credit card data","C Buying cyber insurance","D Deploying a firewall"], correct:1, explanation:"Deciding not to store credit card data eliminates the associated payment data breach risk entirely—this is risk avoidance, removing the risk by not engaging in the risky activity." },
  { id:10278, domain:2, level:2, question:"What is the role of a risk owner?", options:["A To approve all security expenditures","B To eliminate all risks in their area","C To be accountable for monitoring, treating, and reporting on specific risks","D To conduct penetration tests"], correct:2, explanation:"A risk owner is accountable for managing a specific risk, including monitoring its status, ensuring treatment actions are implemented, and reporting progress to management." },
  { id:10279, domain:2, level:2, question:"Which ISO standard provides principles and guidelines for risk management across all types of organizations?", options:["A ISO 31000","B ISO 27005","C ISO 27001","D ISO 22301"], correct:0, explanation:"ISO 31000 provides universal principles and guidelines for risk management applicable to any organization regardless of size, sector, or activity." },
  { id:10280, domain:2, level:2, question:"What does a risk heat map primarily communicate?", options:["A The organization's complete control framework","B The exact financial cost of each risk","C The technical details of vulnerabilities","D The relative likelihood and impact of risks for prioritization"], correct:3, explanation:"A risk heat map visually communicates the relative likelihood and impact of risks, enabling stakeholders to quickly identify and prioritize the most significant risks." },
  { id:10281, domain:2, level:2, question:"When performing a third-party risk assessment, which factor is MOST critical to evaluate?", options:["A The number of employees the vendor has","B The vendor's marketing materials","C The vendor's security controls and their alignment with the organization's risk requirements","D The vendor's stock price"], correct:2, explanation:"Evaluating a vendor's security controls and their alignment with the organization's requirements is critical to determining whether third-party risk is acceptable." },
  { id:10282, domain:2, level:2, question:"What is the BEST way to ensure risk management is integrated into business decisions?", options:["A Conduct annual risk assessments only","B Rely on external auditors for risk identification","C Isolate the risk function within IT security","D Embed risk management into project management and change management processes"], correct:3, explanation:"Embedding risk management into project and change management processes ensures risk considerations are part of every business decision rather than a separate, periodic exercise." },
  { id:10283, domain:2, level:2, question:"An organization's risk assessment identifies a critical vulnerability with high exploitability but low business impact. How should it be prioritized?", options:["A Medium priority based on the combined risk rating of both factors","B Highest priority because exploitability is high","C Lowest priority because impact is low","D Excluded from the risk register"], correct:0, explanation:"Risk priority should reflect the combined rating of both likelihood (exploitability) and impact; high exploitability with low impact typically results in a medium priority rating." },
  { id:10284, domain:2, level:2, question:"Which of the following BEST supports the concept of risk accountability?", options:["A Assigning all risks to the security team","B Delegating risk decisions entirely to external consultants","C Letting each department manage risk independently","D Designating named risk owners with clear responsibilities for each identified risk"], correct:3, explanation:"Designating named risk owners with clear responsibilities creates accountability, ensuring each risk has someone responsible for its monitoring and treatment." },
  { id:10285, domain:2, level:2, question:"What is the PRIMARY output of the NIST SP 800-30 risk assessment process?", options:["A An incident response plan","B A risk register documenting identified risks, likelihood, impact, and recommendations","C A penetration test report","D A list of system patches required"], correct:1, explanation:"NIST SP 800-30 produces a risk assessment report documenting identified risks with their likelihood, impact ratings, and recommendations for risk treatment." },
  { id:10286, domain:2, level:2, question:"How does ISO 27005 relate to risk management?", options:["A It governs third-party audits","B It specifies encryption standards","C It defines physical security standards","D It provides guidelines for information security risk management specifically"], correct:3, explanation:"ISO 27005 provides guidelines for information security risk management, complementing the ISO 27001 ISMS standard with detailed risk assessment and treatment guidance." },
  { id:10287, domain:2, level:2, question:"A risk assessment reveals that a critical business system has no redundancy. Under which BIA metric is this MOST relevant?", options:["A Recovery Time Objective (RTO)","B Maximum Tolerable Downtime (MTD)","C Recovery Point Objective (RPO)","D Mean Time Between Failures (MTBF)"], correct:1, explanation:"Maximum Tolerable Downtime (MTD) defines the longest period a business function can be unavailable; lack of redundancy directly threatens the organization's ability to meet MTD requirements." },
  { id:10288, domain:2, level:2, question:"Which of the following is a leading indicator used in risk monitoring?", options:["A Number of unpatched critical vulnerabilities currently open","B Total cost of breaches over 5 years","C Number of completed security awareness trainings historically","D Number of security incidents in the past year"], correct:0, explanation:"The number of currently open unpatched critical vulnerabilities is a leading (forward-looking) KRI that signals rising risk exposure before an incident occurs." },
  { id:10289, domain:2, level:2, question:"What distinguishes a risk scenario from a risk statement?", options:["A A risk scenario describes a sequence of events; a risk statement identifies a single risk and its consequences","B A risk scenario applies only to IT risks","C A risk scenario is broader, while a risk statement is specific","D They are identical in practice"], correct:0, explanation:"A risk scenario describes a plausible chain of events leading to impact, while a risk statement concisely identifies a specific risk, typically in 'cause-effect' or 'if-then' format." },
  { id:10290, domain:2, level:2, question:"What is the MAIN reason for communicating risk information to senior management?", options:["A To avoid responsibility for security failures","B To enable informed risk-based decision making at the strategic level","C To demonstrate the security team's workload","D To comply with audit requirements only"], correct:1, explanation:"Communicating risk information to senior management ensures they have the information needed for informed, risk-based strategic decisions and appropriate resource allocation." },
  { id:10291, domain:2, level:3, question:"An organization is migrating to cloud infrastructure. Which emerging risk category requires the MOST immediate attention in the risk register update?", options:["A Firewall configuration risks","B Physical security risks","C Cloud-specific risks including shared responsibility, data sovereignty, and provider lock-in","D Insider threat risks that existed before cloud adoption"], correct:2, explanation:"Cloud migration introduces unique risks including shared responsibility model gaps, data sovereignty concerns, and provider dependency that must be assessed and documented immediately in the risk register." },
  { id:10292, domain:2, level:3, question:"A CISM practitioner is asked to justify a $2M security investment to the board. Which approach BEST supports the business case?", options:["A Describe competitor security postures","B Reference compliance mandates only","C Show ALE calculations demonstrating the investment reduces annual expected losses by more than $2M","D Present technical vulnerability details"], correct:2, explanation:"Demonstrating that the investment reduces ALE by more than its cost provides a clear financial return-on-investment argument that resonates with board-level decision makers." },
  { id:10293, domain:2, level:3, question:"An organization discovers a critical supply chain risk after a software vendor is compromised. Which immediate action BEST addresses governance accountability?", options:["A Conduct a new risk assessment from scratch","B Activate the incident response plan and notify the risk owner and senior management","C Wait for the vendor to resolve the issue","D Terminate all vendor relationships"], correct:1, explanation:"Activating incident response and notifying risk owners and senior management ensures proper governance accountability and coordinated response to the supply chain compromise." },
  { id:10294, domain:2, level:3, question:"When should an organization MOST likely choose risk transfer over risk mitigation?", options:["A When residual risk is zero","B When the cost of controls exceeds the risk's financial exposure and insurance is available at lower cost","C When the risk has low impact","D When the threat source is internal"], correct:1, explanation:"Risk transfer is most appropriate when control costs exceed the potential loss and insurance or contractual transfer is available at a lower cost, making it economically superior to mitigation." },
  { id:10295, domain:2, level:3, question:"An information security manager notices that KRIs for a critical process have been consistently at threshold levels for three months. What is the MOST appropriate response?", options:["A Escalate to management and initiate a detailed risk review to determine if treatment plans need revision","B Remove the KRIs as they appear overly sensitive","C Lower the KRI thresholds to reduce false alarms","D Monitor for another month before acting"], correct:0, explanation:"Sustained KRI threshold breaches signal that current risk treatment may be insufficient; escalation and detailed review are necessary to determine whether controls need strengthening." },
  { id:10296, domain:2, level:3, question:"A risk manager must assess IoT devices newly deployed in a manufacturing environment. Which risk characteristic makes IoT devices particularly challenging?", options:["A IoT devices generate too much data for risk analysis","B IoT devices are only a physical security concern","C IoT devices often lack patch management capabilities and run outdated firmware indefinitely","D IoT devices are always connected to the internet"], correct:2, explanation:"IoT devices frequently cannot be patched due to hardware or vendor limitations, creating persistent, unmitigable vulnerabilities that require alternative compensating controls and risk acceptance strategies." },
  { id:10297, domain:2, level:3, question:"During an enterprise risk assessment, two business units report conflicting risk ratings for the same shared system. What is the BEST approach?", options:["A Conduct a joint assessment with both units to reconcile ratings and reflect aggregate organizational risk","B Use the lower rating","C Let each unit maintain its own rating","D Use the higher rating"], correct:0, explanation:"A joint assessment reconciles divergent ratings by incorporating both units' perspectives, producing a unified organizational risk view that reflects the shared system's true aggregate exposure." },
  { id:10298, domain:2, level:3, question:"What is the MOST significant limitation of quantitative risk analysis in information security?", options:["A It depends on reliable historical data that is often unavailable for cyber risks","B It produces results that management cannot understand","C It cannot be used for regulatory compliance","D It requires too many people to conduct"], correct:0, explanation:"Quantitative analysis depends on historical frequency and loss data, which is often sparse or unavailable for cyber events, making estimates less reliable than in mature actuarial fields." },
  { id:10299, domain:2, level:3, question:"An organization's risk treatment plan for a high-rated risk has been delayed six months. What is the risk manager's PRIMARY responsibility?", options:["A Accept the risk without documentation","B Remove the risk from active monitoring","C Blame the responsible team","D Update the risk register, escalate the delay to management, and assess whether interim controls are needed"], correct:3, explanation:"When treatment plans are delayed, the risk manager must document the situation, escalate appropriately, and evaluate whether interim compensating controls are needed to manage elevated exposure." },
  { id:10300, domain:2, level:3, question:"Which approach BEST integrates risk management into an organization's culture?", options:["A Mandating annual risk training","B Conducting quarterly penetration tests","C Embedding risk considerations into daily decision-making through risk champions and leadership tone at the top","D Publishing a risk policy document"], correct:2, explanation:"Cultural integration requires ongoing reinforcement through risk champions, leadership behavior, and embedding risk thinking into routine decisions, not just periodic formal activities." },
  { id:10301, domain:2, level:1, question:"In risk management, what does 'vulnerability' refer to?", options:["A A risk treatment option","B A potential threat actor","C A weakness that can be exploited by a threat","D The financial impact of a security event"], correct:2, explanation:"A vulnerability is a weakness in a system, process, or control that a threat can exploit to cause harm; it is a key factor in risk assessment." },
  { id:10302, domain:2, level:1, question:"Which of the following BEST describes 'risk identification'?", options:["A Calculating the financial impact of risks","B The process of finding, recognizing, and documenting risks","C Implementing controls to address risks","D Accepting risks below a defined threshold"], correct:1, explanation:"Risk identification is the first step in risk management, involving finding, recognizing, and describing risks that could affect the organization's objectives." },
  { id:10303, domain:2, level:1, question:"What is the formula for calculating SLE?", options:["A ALE ÷ ARO","B Asset Value × Exposure Factor","C Threat Probability × Control Cost","D Asset Value × ARO"], correct:1, explanation:"SLE (Single Loss Expectancy) = Asset Value × Exposure Factor, representing the expected monetary loss for each occurrence of the risk event." },
  { id:10304, domain:2, level:1, question:"What is the formula for calculating ALE?", options:["A Asset Value × Threat Probability","B EF × Asset Value × ARO","C SLE × ARO","D SLE + ARO"], correct:2, explanation:"ALE (Annual Loss Expectancy) = SLE × ARO, representing the expected annual financial loss from a specific risk based on occurrence frequency." },
  { id:10305, domain:2, level:1, question:"Which risk assessment approach uses categories such as 'high,' 'medium,' and 'low' rather than specific numbers?", options:["A Qualitative risk assessment","B Quantitative risk assessment","C Monte Carlo simulation","D Factor analysis"], correct:0, explanation:"Qualitative risk assessment uses descriptive categories (high/medium/low) rather than precise numbers, making it practical when detailed data is unavailable." },
  { id:10306, domain:2, level:1, question:"What is the PRIMARY goal of a vendor risk management program?", options:["A To eliminate all vendor relationships","B To ensure vendors comply with all internal policies","C To audit vendors annually","D To ensure third-party risks are identified, assessed, and managed to acceptable levels"], correct:3, explanation:"A vendor risk management program ensures that risks introduced by third-party relationships are identified, assessed, and treated so they remain within the organization's risk tolerance." },
  { id:10307, domain:2, level:1, question:"Which of the following is a threat to information assets?", options:["A Missing encryption","B Unpatched software","C Social engineering attack","D Lack of access controls"], correct:2, explanation:"A social engineering attack is a threat—a potential cause of harm. Unpatched software, missing controls, and lack of encryption are vulnerabilities, not threats." },
  { id:10308, domain:2, level:1, question:"What is the PURPOSE of a risk appetite statement?", options:["A To list all identified risks","B To establish incident response procedures","C To communicate the types and levels of risk management is willing to accept","D To define specific security controls"], correct:2, explanation:"A risk appetite statement communicates management's stance on acceptable risk levels, guiding risk treatment decisions and resource allocation throughout the organization." },
  { id:10309, domain:2, level:1, question:"Which of the following is NOT a standard risk treatment option?", options:["A Risk acceptance","B Risk transfer","C Risk mitigation","D Risk quantification"], correct:3, explanation:"Risk quantification is part of the risk assessment process, not a treatment option. The four standard treatment options are mitigation, transfer, avoidance, and acceptance." },
  { id:10310, domain:2, level:1, question:"What does 'risk mitigation' mean?", options:["A Transferring the risk to an insurer","B Reducing the likelihood or impact of a risk through controls","C Ignoring the risk","D Eliminating risk entirely"], correct:1, explanation:"Risk mitigation involves implementing controls or countermeasures to reduce either the likelihood of a risk event occurring or its impact if it does occur." },
  { id:10311, domain:2, level:2, question:"A security manager is prioritizing which risks to treat first. Which criterion should carry the MOST weight?", options:["A Cost of the recommended control","B Number of vulnerabilities associated with the risk","C Age of the identified risk","D Combined rating of likelihood and business impact"], correct:3, explanation:"Risk prioritization should be driven by the combined assessment of likelihood and business impact, ensuring resources are directed to risks posing the greatest organizational threat." },
  { id:10312, domain:2, level:2, question:"An organization uses cyber insurance as its primary risk treatment for a critical data breach risk. What concern should the CISM raise?", options:["A Insurance transfers financial impact but does not reduce likelihood or operational impact of the breach","B Insurance is never appropriate for cyber risks","C Insurance policies always cover all cyber losses","D The organization should replace cyber insurance with technical controls"], correct:0, explanation:"Cyber insurance transfers financial consequences but does not reduce breach likelihood or operational disruption; the CISM should ensure the organization also has appropriate preventive controls." },
  { id:10313, domain:2, level:2, question:"During a risk assessment, which step involves determining the probability that a specific threat will exploit a vulnerability?", options:["A Risk identification","B Impact analysis","C Likelihood determination","D Risk treatment planning"], correct:2, explanation:"Likelihood determination assesses the probability that a specific threat will successfully exploit a vulnerability, combining threat frequency and vulnerability exploitability." },
  { id:10314, domain:2, level:2, question:"What is the MOST effective way to demonstrate the ROI of a risk management program?", options:["A Count the number of security policies created","B Report the number of security incidents prevented","C Compare risk reduction achieved against the cost of risk management activities","D Show the number of risks identified"], correct:2, explanation:"Demonstrating ROI by comparing quantified risk reduction (in financial or probability terms) against program costs provides a clear, objective measure of value." },
  { id:10315, domain:2, level:2, question:"An asset has a value of $500,000 and an exposure factor of 40%. What is the SLE?", options:["A $100,000","B $200,000","C $300,000","D $500,000"], correct:1, explanation:"SLE = Asset Value × EF = $500,000 × 0.40 = $200,000. This represents the expected monetary loss from a single occurrence of the risk event." },
  { id:10316, domain:2, level:2, question:"If the SLE is $200,000 and the ARO is 0.5, what is the ALE?", options:["A $100,000","B $50,000","C $200,000","D $400,000"], correct:0, explanation:"ALE = SLE × ARO = $200,000 × 0.5 = $100,000. An ARO of 0.5 means the event is expected to occur once every two years." },
  { id:10317, domain:2, level:2, question:"What is the PRIMARY difference between a risk assessment and a vulnerability assessment?", options:["A They are identical processes","B A vulnerability assessment considers business impact","C A risk assessment evaluates likelihood and business impact; a vulnerability assessment identifies technical weaknesses","D A risk assessment only identifies physical risks"], correct:2, explanation:"A vulnerability assessment identifies technical weaknesses in systems, while a risk assessment evaluates the broader business impact and likelihood of those weaknesses being exploited." },
  { id:10318, domain:2, level:2, question:"Which of the following BEST describes 'risk aggregation'?", options:["A The cumulative effect of multiple smaller risks that collectively create a larger organizational risk","B The process of combining risk registers from different departments","C Adding up all ALE values in a risk register","D Assigning risk ratings to unassessed risks"], correct:0, explanation:"Risk aggregation recognizes that multiple individually manageable risks can combine to create a significantly larger aggregate risk that may exceed the organization's tolerance." },
  { id:10319, domain:2, level:2, question:"Which of the following should be included in a risk treatment plan?", options:["A The risk description, treatment option selected, responsible owner, timeline, and success criteria","B Only risks above the high threshold","C Only the recommended control","D The financial cost of the risk only"], correct:0, explanation:"A comprehensive risk treatment plan includes the risk details, chosen treatment approach, accountable owner, implementation timeline, and measurable success criteria." },
  { id:10320, domain:2, level:2, question:"What is the BEST reason for conducting periodic risk reassessments?", options:["A To satisfy audit requirements","B To create more documentation","C Because the threat landscape, business environment, and control effectiveness change over time","D To justify the security budget"], correct:2, explanation:"Periodic reassessments are essential because threats evolve, business processes change, and controls may degrade, meaning yesterday's risk profile may not reflect today's reality." },
  { id:10321, domain:2, level:2, question:"A company plans to adopt a new cloud service. At which stage should risk assessment BEST occur?", options:["A After full deployment","B After the first security audit","C When users report problems","D During initial project planning, before vendor selection"], correct:3, explanation:"Risk assessment should occur during initial planning and before vendor selection, when risk findings can meaningfully influence design decisions and vendor requirements." },
  { id:10322, domain:2, level:2, question:"What is 'secondary risk'?", options:["A A risk identified after the primary assessment is complete","B A new risk introduced by the implementation of a risk treatment","C A risk that affects only non-critical systems","D A risk with medium likelihood and impact"], correct:1, explanation:"Secondary risk is a new risk that arises as a direct result of implementing a risk treatment; these must be assessed to ensure treatments do not create unacceptable new exposures." },
  { id:10323, domain:2, level:2, question:"Which element of the FAIR model quantifies 'loss event frequency'?", options:["A Threat Event Frequency × Vulnerability","B SLE × ARO","C Threat Capability × Resistance Strength","D Asset Value × Exposure Factor"], correct:0, explanation:"In FAIR, Loss Event Frequency is the product of Threat Event Frequency and Vulnerability (the probability that a threat event results in a loss), not ALE calculations." },
  { id:10324, domain:2, level:2, question:"An organization's risk assessment process does not involve business unit managers. What is the MAIN risk of this approach?", options:["A IT risks will be overemphasized","B Critical business context and operational risks may be missed, reducing assessment quality","C The assessment will cost too much","D The assessment will take too long"], correct:1, explanation:"Business unit managers have essential knowledge of operational processes and priorities; excluding them risks producing assessments that miss key business risks and lack organizational relevance." },
  { id:10325, domain:2, level:2, question:"What is the MOST appropriate metric for measuring the effectiveness of risk management?", options:["A Number of security tools deployed","B Number of security policies in place","C Size of the security budget","D Reduction in residual risk levels over time relative to risk appetite"], correct:3, explanation:"The most meaningful measure of risk management effectiveness is whether residual risk levels are decreasing toward or remaining within the organization's defined risk appetite." },
  { id:10326, domain:2, level:2, question:"Which risk management approach BEST supports regulatory compliance requirements?", options:["A Integrating compliance requirements into the enterprise risk management framework","B Managing compliance risks separately from other business risks","C Accepting all compliance-related risks","D Delegating compliance to the legal department"], correct:0, explanation:"Integrating compliance requirements into the ERM framework ensures regulatory risks are managed consistently with other business risks and avoids fragmented or duplicated efforts." },
  { id:10327, domain:2, level:2, question:"What type of risk is introduced when an organization relies on a single vendor for a critical service?", options:["A Reputational risk","B Market risk","C Concentration risk (single point of failure/dependency risk)","D Compliance risk"], correct:2, explanation:"Concentration risk arises from over-reliance on a single vendor, creating a single point of failure; if the vendor fails, the organization has no alternative, amplifying potential impact." },
  { id:10328, domain:2, level:2, question:"When performing vendor due diligence, which document BEST provides evidence of a vendor's security posture?", options:["A Vendor's marketing brochure","B Vendor's price list","C Vendor's employee handbook","D Vendor's SOC 2 Type II audit report"], correct:3, explanation:"A SOC 2 Type II audit report provides independent third-party assurance that a vendor's security controls have been operating effectively over a period of time." },
  { id:10329, domain:2, level:2, question:"Which of the following describes a 'bottom-up' approach to risk identification?", options:["A Starting with strategic objectives and working down to operational risks","B Relying entirely on external threat intelligence","C Starting with systems and processes, identifying technical risks, then mapping to business impact","D Using only management input to identify risks"], correct:2, explanation:"A bottom-up approach starts at the operational or technical level, identifying specific threats and vulnerabilities, then maps them up to business impact and strategic risk." },
  { id:10330, domain:2, level:2, question:"What is the MAIN purpose of a risk communication plan?", options:["A To document all identified risks","B To replace the risk register","C To ensure the right risk information reaches the right stakeholders at the right time","D To satisfy external audit requirements"], correct:2, explanation:"A risk communication plan ensures timely, appropriate risk information flows to relevant stakeholders, enabling informed decisions and maintaining organizational awareness." },
  { id:10331, domain:2, level:3, question:"An organization's board of directors requests a summary of the top 10 risks. Which presentation approach is MOST effective?", options:["A Show the full risk register with all fields","B Present a risk heat map with narrative descriptions of top risks, business impact, and treatment status","C Provide a spreadsheet of all identified risks","D Deliver a technical vulnerability report"], correct:1, explanation:"A heat map with business-focused narrative descriptions conveys risk at a strategic level appropriate for board members who need context and prioritization, not technical detail." },
  { id:10332, domain:2, level:3, question:"An organization has undergone a major acquisition. What is the MOST critical risk management action?", options:["A Focus only on financial integration risks","B Immediately conduct a risk assessment of the acquired entity to identify new risks introduced","C Adopt the acquired entity's risk management framework","D Wait until integration is complete before assessing risks"], correct:1, explanation:"An immediate risk assessment of the acquired entity is critical to understand new risks, identify integration vulnerabilities, and protect both organizations during the transition period." },
  { id:10333, domain:2, level:3, question:"A risk manager discovers that the same risk has been documented in three different departmental risk registers with different ratings. What is the BEST corrective action?", options:["A Conduct a cross-functional risk review to produce a single, authoritative assessment","B Allow each department to keep its own rating","C Use the highest rating","D Use the average of the three ratings"], correct:0, explanation:"A cross-functional review produces a unified, authoritative risk rating that incorporates all relevant perspectives, eliminates inconsistencies, and supports organization-wide risk reporting." },
  { id:10334, domain:2, level:3, question:"Which approach BEST addresses the risk management challenges specific to IoT deployments?", options:["A Applying traditional IT risk management processes without modification","B Treating IoT risks the same as cloud risks","C Developing IoT-specific risk criteria including device lifecycle, patch limitations, and network segmentation risks","D Prohibiting all IoT device usage"], correct:2, explanation:"IoT presents unique risk characteristics (limited patchability, long lifecycle, specialized protocols) requiring tailored risk criteria and controls beyond standard IT risk approaches." },
  { id:10335, domain:2, level:3, question:"An information risk manager is asked to assess risks of a new AI-driven decision-making system. Which risk category is MOST unique to AI systems?", options:["A User authentication risks","B Physical security of servers","C Network availability risk","D Algorithmic bias and model opacity risks affecting decision fairness and accountability"], correct:3, explanation:"AI systems introduce unique risks including algorithmic bias, model opacity (black box decisions), and accountability gaps that require specialized risk criteria beyond standard IT risk frameworks." },
  { id:10336, domain:2, level:3, question:"What is the PRIMARY challenge when applying quantitative risk analysis to cyber risk for executive reporting?", options:["A Executives do not care about financial risk figures","B Cyber loss data is sparse and models rely on assumptions, making estimates uncertain","C Executives prefer technical metrics","D Qualitative methods are always more accurate"], correct:1, explanation:"The primary challenge is data scarcity; cyber risk quantification requires actuarial data that is often unavailable or unreliable, making financial estimates uncertain and requiring transparent assumptions." },
  { id:10337, domain:2, level:3, question:"An organization's risk appetite has decreased due to a major regulatory change. What is the IMMEDIATE required action for the risk manager?", options:["A Wait for the next scheduled risk review","B Review the risk register and identify risks that now exceed the revised appetite, escalating for treatment","C Revise the risk methodology only","D Increase the number of security controls across all systems"], correct:1, explanation:"When risk appetite decreases, risks previously within tolerance may now exceed it; immediate review of the register is required to identify and escalate these risks for treatment." },
  { id:10338, domain:2, level:3, question:"Which of the following BEST describes an enterprise-level risk management approach versus a project-level approach?", options:["A Enterprise risk management takes a holistic view across all strategic, operational, and technology risks organization-wide","B They are identical in scope and methodology","C Enterprise risk management focuses only on financial risks","D Enterprise risk management is less formal than project risk management"], correct:0, explanation:"Enterprise risk management (ERM) takes an integrated, organization-wide view of all risk categories aligned to strategic objectives, whereas project risk management focuses on specific project deliverables." },
  { id:10339, domain:2, level:3, question:"A CISM is preparing to present risk treatment recommendations that require significant budget. Which argument will MOST likely gain executive approval?", options:["A Frame the investment as risk reduction that protects specific business value, using quantified loss scenarios","B Show compliance checklist completion rates","C Cite the number of vulnerabilities found","D Reference competitor security spending"], correct:0, explanation:"Executives approve security investments when they are framed as protecting quantified business value; loss scenarios using financial figures connect security investment directly to business outcomes." },
  { id:10340, domain:2, level:3, question:"When designing a risk monitoring program, what is the MOST important consideration for selecting KRIs?", options:["A KRIs should be identical across all organizations","B KRIs should cover as many risks as possible","C KRIs should be easy to collect from existing systems","D KRIs should be forward-looking, measurable, and directly correlated to the risk they are designed to signal"], correct:3, explanation:"Effective KRIs must be forward-looking to provide early warning, measurable for consistency, and clearly correlated to specific risks to be actionable and meaningful." },
  { id:10341, domain:2, level:1, question:"Which of the following is the FIRST step in the risk management process?", options:["A Risk identification","B Risk treatment","C Risk communication","D Risk monitoring"], correct:0, explanation:"Risk identification is the first step, as risks must be found and documented before they can be analyzed, treated, or monitored." },
  { id:10342, domain:2, level:1, question:"What does 'risk acceptance' formally require?", options:["A Notification to regulators","B Implementing a compensating control","C External audit approval","D Documented acknowledgment by an authorized decision-maker that the risk exists and is within tolerance"], correct:3, explanation:"Formal risk acceptance requires documented acknowledgment by an appropriate authority that the risk has been reviewed and is acceptable, creating an audit trail of the decision." },
  { id:10343, domain:2, level:1, question:"Which of the following BEST describes the relationship between threats, vulnerabilities, and risk?", options:["A Vulnerability determines risk without considering threats","B Risk = Threat + Vulnerability","C Threat and vulnerability are synonymous","D Risk is the potential harm when a threat exploits a vulnerability"], correct:3, explanation:"Risk is the potential harm (impact × likelihood) that results when a threat successfully exploits a vulnerability; all three elements must be considered in risk assessment." },
  { id:10344, domain:2, level:1, question:"What is a 'risk scenario' primarily used for in information risk management?", options:["A To create realistic narratives that help assess the likelihood and impact of specific risk events","B To document past incidents","C To define security policies","D To track control implementation status"], correct:0, explanation:"Risk scenarios create realistic, plausible narratives of how risks could materialize, helping assessors evaluate likelihood and impact more concretely than abstract risk statements." },
  { id:10345, domain:2, level:1, question:"Which risk management framework defines risk as 'effect of uncertainty on objectives'?", options:["A OCTAVE","B FAIR","C NIST SP 800-30","D ISO 31000"], correct:3, explanation:"ISO 31000 defines risk as the 'effect of uncertainty on objectives,' a broader definition that encompasses both positive and negative outcomes, unlike security-focused definitions." },
  { id:10346, domain:2, level:1, question:"What type of analysis estimates the probability distribution of outcomes using random sampling?", options:["A Monte Carlo simulation","B Bow-tie analysis","C Fault tree analysis","D Delphi method"], correct:0, explanation:"Monte Carlo simulation uses random sampling to model probability distributions of outcomes, enabling quantitative risk analysis when precise input values are uncertain." },
  { id:10347, domain:2, level:1, question:"Which of the following represents a risk treatment that reduces the likelihood of a risk?", options:["A Cyber insurance","B Discontinuing a business process","C Multi-factor authentication","D Risk acceptance documentation"], correct:2, explanation:"Multi-factor authentication reduces the likelihood of unauthorized access by adding an additional authentication layer, directly reducing the probability of the risk event occurring." },
  { id:10348, domain:2, level:1, question:"What is the purpose of a risk assessment scope statement?", options:["A To define the boundaries, objectives, and assets included in the risk assessment","B To list all identified risks","C To document risk treatment decisions","D To assign risk owners"], correct:0, explanation:"A scope statement defines what is included in and excluded from the risk assessment, ensuring assessors focus on relevant assets, processes, and systems." },
  { id:10349, domain:2, level:1, question:"Which of the following is an example of an operational risk?", options:["A Currency exchange fluctuations","B Interest rate changes","C New competitor entering the market","D Failure of a critical business process due to human error"], correct:3, explanation:"Operational risk arises from failures in internal processes, people, or systems; a process failure due to human error is a classic operational risk example." },
  { id:10350, domain:2, level:1, question:"What is 'residual risk acceptance'?", options:["A Accepting risk before any controls are applied","B Transferring residual risk to insurers","C Documenting all risk events in the risk register","D Formal management acknowledgment that remaining risk after controls is acceptable"], correct:3, explanation:"Residual risk acceptance is management's formal acknowledgment that after controls are applied, the remaining risk is at or below the acceptable threshold." },
  { id:10351, domain:2, level:2, question:"A risk assessment shows that a legacy system has critical vulnerabilities that cannot be patched. What is the BEST risk treatment approach?", options:["A Accept the risk without any action","B Transfer the risk through insurance only","C Implement compensating controls such as network isolation, enhanced monitoring, and access restrictions","D Immediately decommission the system"], correct:2, explanation:"When patching is not possible, compensating controls—isolation, enhanced monitoring, access restrictions—reduce risk exposure while a long-term remediation plan is developed." },
  { id:10352, domain:2, level:2, question:"Which of the following BEST describes the 'tone at the top' in risk management?", options:["A The first risk identified in an assessment","B Senior leadership demonstrating commitment to risk management through actions and communications","C The highest risk rating in the risk register","D The most urgent risk requiring immediate treatment"], correct:1, explanation:"'Tone at the top' refers to senior leadership's visible commitment to risk management, which shapes organizational culture and drives risk-aware behavior throughout the organization." },
  { id:10353, domain:2, level:2, question:"What is the MAIN purpose of a risk management policy?", options:["A To document past risk decisions","B To list all security controls","C To replace the risk register","D To define the organization's approach, responsibilities, and requirements for managing risk"], correct:3, explanation:"A risk management policy establishes the organizational framework for risk management, defining objectives, roles, responsibilities, and the overall approach to risk." },
  { id:10354, domain:2, level:2, question:"An organization wants to reduce its attack surface. Which risk treatment approach does this represent?", options:["A Risk mitigation","B Risk acceptance","C Risk transfer","D Risk avoidance"], correct:0, explanation:"Reducing the attack surface by removing unnecessary services, closing ports, or restricting access directly reduces the likelihood of exploitation—this is risk mitigation." },
  { id:10355, domain:2, level:2, question:"A new regulatory requirement mandates data encryption for all customer records. How does this affect the organization's risk posture?", options:["A It has no effect on risk until implemented","B It eliminates the risk of data breaches","C It reduces the impact of a data breach by protecting confidentiality of customer data","D It increases operational risk"], correct:2, explanation:"Encrypting customer records reduces the business impact of a data breach by ensuring stolen data is unusable without the encryption key, reducing breach severity." },
  { id:10356, domain:2, level:2, question:"Which of the following BEST describes a 'top-down' risk assessment approach?", options:["A Starting with strategic objectives and identifying risks that could prevent their achievement","B Starting with technical vulnerabilities and mapping upward to business impact","C Using only automated scanning tools","D Focusing exclusively on external threats"], correct:0, explanation:"A top-down approach begins with organizational strategies and objectives, then identifies risks that threaten their achievement, ensuring alignment with business priorities." },
  { id:10357, domain:2, level:2, question:"When should a risk be escalated beyond a risk owner's authority?", options:["A When the risk involves external parties","B When residual risk exceeds the risk owner's delegated risk acceptance authority","C When the risk is more than one year old","D When the risk is rated as low"], correct:1, explanation:"Escalation is required when residual risk exceeds the risk owner's delegated authority, ensuring decisions are made at the appropriate level with adequate authority and accountability." },
  { id:10358, domain:2, level:2, question:"Which of the following BEST describes 'risk velocity'?", options:["A The cost to remediate a risk","B The frequency of risk assessments","C The rate at which new risks are identified","D The speed at which a risk can materialize and impact the organization"], correct:3, explanation:"Risk velocity describes how quickly a risk can escalate from identification to impact, helping prioritize risks that could cause rapid, severe harm if not addressed promptly." },
  { id:10359, domain:2, level:2, question:"What is the PRIMARY benefit of maintaining a risk register?", options:["A It replaces the need for security controls","B It satisfies all regulatory requirements","C It provides a central repository for tracking risks, their status, and treatment progress","D It eliminates the need for risk assessments"], correct:2, explanation:"A risk register centralizes all identified risks with their ratings, owners, treatment plans, and status, enabling consistent tracking, reporting, and accountability." },
  { id:10360, domain:2, level:2, question:"Which of the following describes 'risk interdependencies'?", options:["A Risks shared between departments","B Relationships between risks where one risk event can trigger or amplify another","C Risks that affect multiple organizations simultaneously","D All risks in the same risk category"], correct:1, explanation:"Risk interdependencies are relationships where one risk event can trigger, amplify, or cascade into other risks, requiring analysis beyond isolated risk assessment." },
  { id:10361, domain:2, level:3, question:"A CISM practitioner is building a third-party risk management program from scratch. What is the MOST critical first step?", options:["A Audit all existing vendor contracts","B Implement a vendor assessment questionnaire","C Require SOC 2 reports from all vendors","D Define vendor risk tiers based on the criticality and sensitivity of services provided"], correct:3, explanation:"Tiering vendors by criticality and data sensitivity is foundational; it determines what level of due diligence each vendor requires, enabling proportionate resource allocation." },
  { id:10362, domain:2, level:3, question:"An organization's risk management program identifies a risk that is above risk tolerance but treatment costs are prohibitive. What is the MOST appropriate governance response?", options:["A Accept the risk without documentation","B Transfer the risk without further analysis","C Reduce the risk rating to bring it within tolerance","D Escalate to the board for explicit risk acceptance with a documented exception and remediation roadmap"], correct:3, explanation:"When treatment is prohibitive and risk exceeds tolerance, board-level explicit acceptance with documentation and a remediation roadmap ensures appropriate governance and accountability." },
  { id:10363, domain:2, level:3, question:"What is the MOST significant risk introduced by shadow IT (unsanctioned technology use)?", options:["A Unknown risk exposure from systems operating outside the organization's risk management and security controls","B Reduced employee productivity","C Increased IT costs","D Software licensing violations only"], correct:0, explanation:"Shadow IT creates unknown risk exposure because unsanctioned systems operate outside established security controls, compliance oversight, and risk assessment processes." },
  { id:10364, domain:2, level:3, question:"An organization is considering whether to build or buy a critical application. How should risk management inform this decision?", options:["A Risk management is not relevant to build-vs-buy decisions","B Always prefer building to maintain control","C Assess risks unique to each option, including development risk, vendor dependency, and long-term support risk","D Always prefer buying to reduce risk"], correct:2, explanation:"Both options carry unique risks; build introduces development, timeline, and skills risks while buy introduces vendor dependency and customization risks—comprehensive comparison informs the best decision." },
  { id:10365, domain:2, level:3, question:"A risk manager must assess the organization's exposure to ransomware. Which combination of factors is MOST important to evaluate?", options:["A Office layout and physical security","B Employee count and geographic location","C Firewall configuration and network speed","D Backup integrity, email security, endpoint protection, and incident response readiness"], correct:3, explanation:"Ransomware risk assessment requires evaluating the effectiveness of preventive controls (email security, endpoint protection) and resilience factors (backup integrity, incident response) together." },
  { id:10366, domain:2, level:3, question:"What is the MOST critical factor distinguishing effective risk communication from mere reporting?", options:["A Sending reports on a fixed schedule","B Using standardized templates","C Including all technical details","D Tailoring message content, format, and detail level to the specific audience's decision-making needs"], correct:3, explanation:"Effective risk communication tailors content and format to the audience's role and decision needs; board members need strategic context while technical teams need operational detail." },
  { id:10367, domain:2, level:3, question:"An organization's IT infrastructure undergoes rapid change due to digital transformation. What risk management challenge does this create?", options:["A Risk registers become outdated faster, requiring more frequent reassessment cycles","B Compliance requirements become less relevant","C Risk assessments take longer to complete","D Security tools become obsolete"], correct:0, explanation:"Rapid change causes risk profiles to evolve quickly, requiring more frequent risk reassessments and dynamic risk monitoring to keep the risk register current and relevant." },
  { id:10368, domain:2, level:3, question:"A security manager is evaluating residual risk after implementing new controls. Which approach provides the MOST accurate measure?", options:["A Assume controls are fully effective immediately after implementation","B Re-test control effectiveness through testing, measurement, and validation before updating residual risk ratings","C Use the same residual risk rating as before implementation","D Re-assess the risk rating purely based on the control documentation"], correct:1, explanation:"Actual control testing and validation provides evidence-based residual risk ratings; assuming controls are effective without testing may overestimate risk reduction." },
  { id:10369, domain:2, level:3, question:"What is the PRIMARY risk management challenge when operating in multi-cloud environments?", options:["A Fragmented visibility and inconsistent risk assessment across multiple provider environments and shared responsibility models","B Faster data transfer speeds","C More complex user authentication","D Higher storage costs"], correct:0, explanation:"Multi-cloud environments fragment risk visibility across providers with different security models and shared responsibility boundaries, requiring unified risk management approaches that span all environments." },
  { id:10370, domain:2, level:3, question:"How should an information risk manager handle a situation where business units resist the risk assessment process?", options:["A Force compliance through mandatory policy","B Conduct assessments without business unit input","C Engage business leadership to demonstrate how risk management protects business objectives and simplify the process","D Reduce the scope of the risk assessment"], correct:2, explanation:"Demonstrating business value and simplifying participation builds buy-in; resistance often stems from perceived burden or irrelevance, which engagement and simplification can address." },
  { id:10371, domain:2, level:1, question:"Which of the following is the BEST description of 'risk appetite vs. risk capacity'?", options:["A Risk appetite is always higher than risk capacity","B Risk capacity is the maximum risk an organization can absorb; risk appetite is the amount it chooses to accept","C Risk capacity refers only to financial risks","D They are identical concepts"], correct:1, explanation:"Risk capacity is the objective maximum risk an organization can sustain without existential threat, while risk appetite is management's chosen acceptable level, which must not exceed capacity." },
  { id:10372, domain:2, level:1, question:"What is a 'critical asset' in the context of risk management?", options:["A Any asset listed in the asset inventory","B An asset whose compromise would significantly impact the organization's ability to achieve its objectives","C Any IT asset connected to the internet","D The most expensive asset owned by the organization"], correct:1, explanation:"A critical asset is one that is essential to achieving business objectives; its compromise, loss, or disruption would cause significant business impact." },
  { id:10373, domain:2, level:1, question:"Which of the following BEST describes 'likelihood' in risk assessment?", options:["A The financial cost of a risk event","B The impact severity of a risk event","C The number of vulnerabilities in a system","D The probability that a risk event will occur within a defined time period"], correct:3, explanation:"Likelihood is the estimated probability that a specific risk event will occur within a defined time frame, typically one year, combining threat frequency and vulnerability exploitability." },
  { id:10374, domain:2, level:1, question:"What is the relationship between a control and residual risk?", options:["A Residual risk is calculated before controls are considered","B Effective controls reduce residual risk by lowering likelihood or impact","C Controls have no effect on residual risk","D Controls increase residual risk"], correct:1, explanation:"Controls reduce residual risk by lowering the likelihood of the risk event occurring, reducing its impact if it does occur, or both." },
  { id:10375, domain:2, level:1, question:"Which of the following is an example of a reputational risk?", options:["A A software bug causing application errors","B Negative media coverage following a data breach","C A server hardware failure","D An expired SSL certificate"], correct:1, explanation:"Reputational risk arises when events damage stakeholder trust; negative media coverage following a data breach is a classic example of reputational risk materializing." },
  { id:10376, domain:2, level:2, question:"An organization's risk assessment team finds a critical vulnerability affecting a system that processes only publicly available information. How should this risk be rated?", options:["A Critical, because the vulnerability is severe","B Lower than if sensitive data were involved, because impact is reduced by the non-sensitive nature of the data","C The same regardless of data sensitivity","D This should be excluded from the risk register"], correct:1, explanation:"Risk ratings reflect both likelihood and impact; a critical vulnerability in a system handling only public data has lower potential impact than the same vulnerability in a sensitive data system." },
  { id:10377, domain:2, level:2, question:"Which of the following is a key component of effective risk governance?", options:["A Outsourcing all risk decisions to consultants","B Managing risk solely within the IT department","C Clear roles, responsibilities, escalation paths, and board-level oversight of significant risks","D Avoiding formal documentation of risk decisions"], correct:2, explanation:"Effective risk governance requires defined roles, responsibilities, escalation paths, and appropriate board involvement to ensure accountability and informed decision-making." },
  { id:10378, domain:2, level:2, question:"What is the PRIMARY purpose of a risk heat map presented to senior management?", options:["A To list all technical vulnerabilities","B To document control implementation status","C To replace the formal risk register","D To visually prioritize risks by likelihood and impact, facilitating strategic resource allocation"], correct:3, explanation:"A heat map provides a strategic visual summary that helps senior management quickly identify the most significant risks and make informed resource allocation and treatment decisions." },
  { id:10379, domain:2, level:2, question:"An organization implements a security control that introduces new operational complexity. What risk category does the resulting complexity create?", options:["A Operational risk from control failure, misconfiguration, or human error","B Compliance risk","C Financial risk","D Strategic risk"], correct:0, explanation:"Complex controls introduce operational risk through potential misconfiguration, human error in operation, and increased failure modes that may undermine the intended security benefit." },
  { id:10380, domain:2, level:2, question:"Which of the following describes the concept of 'defense in depth' from a risk management perspective?", options:["A Accepting risk at each layer separately","B Using a single, highly effective control","C Relying on perimeter security alone","D Implementing multiple layered controls so that failure of any single control does not result in unacceptable risk"], correct:3, explanation:"Defense in depth reduces risk by layering controls; if one fails, others remain, preventing a single point of failure from resulting in unacceptable impact." },
  { id:10381, domain:2, level:2, question:"Which stakeholder group typically has final authority to approve the organization's risk appetite statement?", options:["A The IT risk team","B The CISO","C External auditors","D The board of directors or senior executive leadership"], correct:3, explanation:"The board or senior executive leadership sets and approves risk appetite as a strategic governance responsibility, reflecting stakeholder expectations and the organization's strategic objectives." },
  { id:10382, domain:2, level:2, question:"What is the PRIMARY risk associated with inadequate security requirements in vendor contracts?", options:["A Increased operational costs","B The organization may have no recourse if a vendor causes a data breach or security incident","C Employee morale may decrease","D Vendors may overcharge for services"], correct:1, explanation:"Without security requirements in contracts, the organization lacks legal recourse and clear expectations when vendor security failures cause incidents, leaving the organization exposed." },
  { id:10383, domain:2, level:2, question:"An emerging threat intelligence report identifies a new attack technique targeting the organization's industry. What is the IMMEDIATE risk management action?", options:["A Ignore the report if no incidents have occurred","B Wait for the next scheduled risk review","C Assess whether current controls address the new technique and update affected risk entries accordingly","D Implement new controls immediately without assessment"], correct:2, explanation:"New threat intelligence requires immediate assessment against current controls to determine if risk ratings need updating and whether additional treatment is required before an incident occurs." },
  { id:10384, domain:2, level:2, question:"What is the MAIN reason organizations perform risk-based prioritization of security investments?", options:["A To spend the security budget as quickly as possible","B To satisfy auditors that all risks are treated","C Resources are finite and should be directed to controls that address the most significant risks","D To avoid any formal risk assessment processes"], correct:2, explanation:"Risk-based prioritization ensures limited security resources are allocated to address the most significant risks first, maximizing the overall reduction in organizational risk exposure." },
  { id:10385, domain:2, level:2, question:"Which of the following BEST describes the concept of 'risk culture'?", options:["A The organization's risk management methodology","B The risk appetite level established by the board","C The shared values, attitudes, and behaviors regarding risk across the organization","D The number of risks identified organization-wide"], correct:2, explanation:"Risk culture encompasses the shared values, attitudes, and behaviors that determine how risk is understood, communicated, and managed at all levels of the organization." },
  { id:10386, domain:2, level:2, question:"What is the significance of a 'risk threshold' in risk management?", options:["A The time limit for completing a risk assessment","B The minimum cost at which a risk must be treated","C The maximum number of risks allowed in a register","D The level at which a risk requires escalation or specific treatment action"], correct:3, explanation:"Risk thresholds define trigger points at which risks require escalation, specific treatment actions, or management decisions, operationalizing risk appetite into actionable criteria." },
  { id:10387, domain:2, level:3, question:"A CISM practitioner is developing a risk management framework for a highly regulated financial institution. Which consideration is MOST critical?", options:["A Keeping the framework as simple as possible","B Aligning the framework with industry-specific regulatory requirements while maintaining flexibility for emerging risks","C Outsourcing risk assessment to consultants","D Using only quantitative risk analysis"], correct:1, explanation:"Regulatory alignment is non-negotiable for financial institutions, but the framework must also be flexible enough to address evolving risks beyond current regulatory requirements." },
  { id:10388, domain:2, level:3, question:"Which approach BEST addresses the challenge of measuring the effectiveness of risk acceptance decisions over time?", options:["A Establish periodic reviews of accepted risks against actual outcomes and changes in the threat landscape","B Remove accepted risks from the register","C Accept all risks permanently once documented","D Review accepted risks only when incidents occur"], correct:0, explanation:"Periodic reviews of accepted risks compare actual outcomes against assumptions, determine if risk levels have changed, and ensure acceptance decisions remain valid given evolving conditions." },
  { id:10389, domain:2, level:3, question:"An organization with global operations faces different regulatory requirements for data security in multiple jurisdictions. What is the BEST risk management approach?", options:["A Identify the most stringent requirements and build a unified baseline that satisfies all jurisdictions","B Apply only local requirements to each regional operation","C Apply the least restrictive jurisdiction's requirements globally","D Manage each jurisdiction's risks independently"], correct:0, explanation:"A unified baseline meeting the most stringent requirements ensures global compliance, reduces complexity, and prevents gaps when requirements differ across jurisdictions." },
  { id:10390, domain:2, level:3, question:"A risk manager is asked to assess the risk of a planned merger. Which risk category deserves the MOST attention during due diligence?", options:["A Network infrastructure differences","B Differences in project management methodologies","C Unknown security liabilities and inherited risks from the target organization","D Employee headcount discrepancies"], correct:2, explanation:"Merger due diligence must uncover unknown security liabilities and inherited risks (breaches, vulnerabilities, compliance gaps) that could become the acquiring organization's liability post-merger." },
  { id:10391, domain:2, level:1, question:"What is a 'risk assessment methodology'?", options:["A A technology platform for risk management","B A tool for blocking threats automatically","C A list of all known threats","D A structured, documented approach for identifying, analyzing, and evaluating risks consistently"], correct:3, explanation:"A risk assessment methodology defines the structured approach—steps, scales, criteria, and documentation—used to assess risks consistently and comparably across the organization." },
  { id:10392, domain:2, level:1, question:"Which of the following is an example of a technical vulnerability?", options:["A A hurricane threatening the data center","B An employee clicking a phishing link","C A firewall misconfiguration that allows unrestricted inbound traffic","D A vendor losing a backup tape"], correct:2, explanation:"A firewall misconfiguration is a technical vulnerability—a weakness in a system configuration that could be exploited by a threat to cause harm." },
  { id:10393, domain:2, level:1, question:"What does 'risk treatment' refer to?", options:["A Documenting risks in a register","B The process of selecting and implementing actions to address assessed risks","C Identifying risks in a system","D Communicating risks to stakeholders"], correct:1, explanation:"Risk treatment involves selecting and implementing the most appropriate option (mitigate, transfer, avoid, or accept) to address each identified and assessed risk." },
  { id:10394, domain:2, level:1, question:"What is the role of 'threat intelligence' in risk management?", options:["A To document past security incidents only","B To provide current information about threats that improves the accuracy of likelihood assessments","C To define the organization's risk appetite","D To replace formal risk assessments"], correct:1, explanation:"Threat intelligence provides current, contextual information about active threats and attacker capabilities, improving the accuracy of likelihood assessments in risk analysis." },
  { id:10395, domain:2, level:1, question:"Which of the following describes a 'risk exception'?", options:["A A formal, time-limited approval to deviate from risk policy when an exception is justified","B A risk that is automatically accepted","C A risk that has been transferred to insurers","D A risk that is excluded from the risk register"], correct:0, explanation:"A risk exception is a formally documented, time-limited deviation from risk policy, requiring appropriate authorization and typically including a remediation plan." },
  { id:10396, domain:2, level:2, question:"An organization's BIA identifies that a critical financial system must be recovered within 4 hours. Which risk scenario is MOST relevant?", options:["A A phishing email targeting employees","B A ransomware attack that encrypts the financial system, requiring recovery from backup","C A minor network performance issue","D A social media reputational incident"], correct:1, explanation:"A ransomware attack directly threatens the system's availability and recovery time; this scenario is most relevant to BIA recovery objectives for a critical financial system." },
  { id:10397, domain:2, level:2, question:"Which metric BEST measures the effectiveness of a risk treatment in reducing the likelihood of a risk?", options:["A Time taken to implement the control","B Total cost of the control","C Number of vulnerabilities found","D Reduction in the KRI value or risk rating after control implementation"], correct:3, explanation:"Reduction in KRI values or risk ratings after control implementation provides direct evidence that the treatment has successfully reduced the likelihood of the risk event." },
  { id:10398, domain:2, level:2, question:"An organization's information security team identifies a zero-day vulnerability with no available patch. What is the BEST risk treatment approach?", options:["A Remove the affected system from service permanently","B Transfer the risk through insurance","C Accept the risk and wait for a vendor patch","D Implement compensating controls to reduce exposure while monitoring for vendor patches"], correct:3, explanation:"Compensating controls (network isolation, enhanced monitoring, access restrictions) reduce exposure from a zero-day vulnerability while awaiting vendor remediation, balancing security and availability." },
  { id:10399, domain:2, level:2, question:"Which of the following BEST describes the concept of 'control risk'?", options:["A The risk that controls fail to operate as intended, leaving the organization exposed","B The risk that too many controls are implemented","C The risk that controls are not documented","D The risk that implemented controls are too expensive"], correct:0, explanation:"Control risk is the risk that controls fail to operate effectively, whether due to misconfiguration, human error, or design flaws, leaving residual risk higher than assumed." },
  { id:10400, domain:2, level:2, question:"What is the MAIN advantage of using OCTAVE Allegro over the original OCTAVE method?", options:["A It is streamlined for smaller organizations and focuses on critical assets without requiring organizational infrastructure analysis","B It is exclusively for financial institutions","C It produces more quantitative results","D It is more technically detailed"], correct:0, explanation:"OCTAVE Allegro is a streamlined version designed for organizations that lack resources for the full OCTAVE methodology, focusing on critical information assets rather than requiring extensive organizational assessment." },
  { id:10401, domain:2, level:3, question:"A CISM practitioner discovers that the organization's risk management program does not address supply chain software risks. What is the BEST first step?", options:["A Immediately quarantine all third-party software","B Conduct a gap assessment to identify unmanaged supply chain risks and prioritize them for inclusion in the risk register","C Wait until a supply chain incident occurs","D Require all vendors to adopt ISO 27001"], correct:1, explanation:"A gap assessment identifies which supply chain software risks are not currently managed, enabling prioritized, structured inclusion in the risk management program." },
  { id:10402, domain:2, level:3, question:"An organization's risk assessment reveals that a key process relies on a single individual with unique knowledge. How should this risk be classified and treated?", options:["A Low risk because the person is trustworthy","B Transfer the risk to the individual's manager","C Key person dependency risk; treated by knowledge documentation, cross-training, and succession planning","D Strategic risk only, not an operational concern"], correct:2, explanation:"Key person dependency is an operational risk that should be treated through knowledge documentation, cross-training, and succession planning to eliminate the single point of failure." },
  { id:10403, domain:2, level:3, question:"During a risk review, a control that was rated as highly effective last year now appears to be partially effective. What is the APPROPRIATE risk management response?", options:["A Remove the control from the risk register","B Re-assess the residual risk upward to reflect reduced control effectiveness and initiate control improvement","C Accept the increased residual risk without documentation","D Maintain the previous residual risk rating"], correct:1, explanation:"Reduced control effectiveness increases residual risk; the risk register must be updated to reflect this change and improvement actions must be initiated to restore adequate protection." },
  { id:10404, domain:2, level:3, question:"A newly appointed CISO wants to establish a risk-based security strategy. What is the MOST important foundation for this strategy?", options:["A Achieving compliance with all applicable regulations","B A comprehensive, current risk assessment aligned with business objectives and risk appetite","C Building a large security team","D Deploying the latest security technologies"], correct:1, explanation:"A risk-based security strategy must be grounded in a current, comprehensive risk assessment that reflects actual organizational risks and aligns security investments with business priorities." },
  { id:10405, domain:2, level:3, question:"What is the GREATEST challenge in applying quantitative risk methods to emerging risks such as AI bias or quantum computing threats?", options:["A Lack of historical data and established loss models makes financial quantification highly uncertain","B Quantitative methods are too simple for these risks","C These risks cannot be included in a risk register","D Management does not understand quantitative methods"], correct:0, explanation:"Emerging risks lack the historical frequency and loss data needed for reliable quantitative analysis, requiring scenario-based approaches with explicit uncertainty acknowledgment." },
  { id:10406, domain:2, level:1, question:"In a risk matrix, what does a risk plotted in the upper-right quadrant typically represent?", options:["A High likelihood, low impact","B High likelihood, high impact—the highest priority for treatment","C Low likelihood, low impact","D Low likelihood, high impact"], correct:1, explanation:"Upper-right quadrant risks combine high likelihood with high impact, representing the greatest threat to the organization and the highest priority for immediate risk treatment." },
  { id:10407, domain:2, level:1, question:"What is the purpose of including 'risk context' in a risk assessment?", options:["A To satisfy documentation requirements","B To replace the risk register","C To list all possible threats","D To ensure risk ratings reflect the organization's specific operating environment, objectives, and stakeholders"], correct:3, explanation:"Risk context ensures assessments reflect the organization's unique environment, business objectives, regulatory landscape, and stakeholder expectations, making risk ratings meaningful and actionable." },
  { id:10408, domain:2, level:1, question:"Which of the following is an example of a physical security threat to information assets?", options:["A Phishing email campaign","B Denial of service attack","C Unauthorized physical access to a server room","D SQL injection attack"], correct:2, explanation:"Unauthorized physical access to a server room is a physical threat that could result in theft, destruction, or compromise of information assets stored on physical hardware." },
  { id:10409, domain:2, level:1, question:"What does 'risk avoidance' sacrifice compared to other risk treatment options?", options:["A Regulatory compliance","B The potential benefits associated with the risky activity","C Risk reduction","D Control costs"], correct:1, explanation:"Risk avoidance eliminates the risk by not undertaking the activity, but also sacrifices any potential benefits or opportunities that the avoided activity would have provided." },
  { id:10410, domain:2, level:1, question:"What type of risk assessment is MOST suitable for a quick, high-level review of a new project?", options:["A Monte Carlo simulation","B FAIR analysis","C Qualitative risk assessment using standard risk criteria","D Full quantitative risk assessment"], correct:2, explanation:"A qualitative risk assessment using standard criteria is practical for quick, high-level project reviews, requiring less data and time than quantitative methods while still identifying significant risks." },
  { id:10411, domain:2, level:2, question:"An organization's employees regularly bypass security controls to complete their work faster. From a risk perspective, what does this MOST indicate?", options:["A Controls may be creating excessive friction, indicating a need to redesign controls to be both effective and usable","B Employees are a security threat","C The organization should implement more restrictive controls","D The risk assessment is incorrect"], correct:0, explanation:"Widespread control bypass signals that controls are too burdensome; risk management must balance security effectiveness with usability to prevent the human factor from undermining control objectives." },
  { id:10412, domain:2, level:2, question:"What is the MOST appropriate frequency for reviewing the risk register in a high-change environment?", options:["A Annually","B Only when a security incident occurs","C Every five years","D Quarterly or more frequently, with event-triggered reviews for significant changes"], correct:3, explanation:"High-change environments require frequent, regular reviews supplemented by event-triggered reviews whenever significant changes occur, ensuring the risk register remains current." },
  { id:10413, domain:2, level:2, question:"Which of the following BEST describes the purpose of the NIST Cybersecurity Framework's 'Identify' function?", options:["A Detecting cybersecurity events","B Recovering from cybersecurity events","C Developing organizational understanding of cybersecurity risk to systems, assets, and data","D Responding to detected incidents"], correct:2, explanation:"The NIST CSF 'Identify' function focuses on developing organizational understanding of cybersecurity risk, encompassing asset management, risk assessment, and governance." },
  { id:10414, domain:2, level:2, question:"What is the PRIMARY risk associated with using default configurations on security devices?", options:["A Compliance violations only","B Increased hardware costs","C Reduced system performance","D Default configurations often have known weaknesses that are publicly documented and easily exploited"], correct:3, explanation:"Default configurations are widely known and often include weak passwords, open ports, and disabled security features, making them easy targets for exploitation by attackers." },
  { id:10415, domain:2, level:2, question:"Which of the following BEST describes 'risk consolidation' in enterprise risk management?", options:["A Aggregating risk information from multiple sources into a unified organizational view","B Treating multiple risks with a single control","C Combining risk registers from different departments arbitrarily","D Reducing the total number of risks"], correct:0, explanation:"Risk consolidation aggregates risk information from across the organization into a unified enterprise view, enabling management to understand total risk exposure and interdependencies." },
  { id:10416, domain:2, level:2, question:"An organization notices that the same asset is listed under different names in multiple risk assessments. What is the BEST corrective action?", options:["A Delete the duplicate entries","B Establish a definitive asset inventory and ensure consistent naming across all risk management activities","C Create separate risk assessments for each name","D Continue with multiple names for flexibility"], correct:1, explanation:"A definitive asset inventory with consistent naming ensures assets are tracked accurately across assessments, preventing gaps or duplications that could skew risk analysis." },
  { id:10417, domain:2, level:2, question:"Which of the following BEST describes how risk management supports the business case for security investments?", options:["A By listing all compliance requirements","B By counting the number of threats identified","C By quantifying risk reduction achieved per dollar invested, enabling cost-benefit comparison","D By documenting all past incidents"], correct:2, explanation:"Risk management supports security investment decisions by quantifying how much risk reduction a proposed control provides relative to its cost, enabling rational, data-driven prioritization." },
  { id:10418, domain:2, level:2, question:"What is the MAIN benefit of automating KRI collection and reporting?", options:["A It makes risk reporting more complex","B It eliminates the need for human risk analysts","C It replaces the risk register","D It enables more frequent, consistent, and timely risk monitoring with reduced manual effort"], correct:3, explanation:"Automated KRI collection provides timely, consistent data with less manual effort, enabling more frequent monitoring and faster detection of rising risk levels." },
  { id:10419, domain:2, level:2, question:"Which of the following describes a 'risk-based audit approach'?", options:["A Auditing only IT systems","B Auditing every control in the organization equally","C Focusing audit resources on areas with the highest risk ratings","D Auditing based on the size of each department"], correct:2, explanation:"A risk-based audit approach concentrates audit resources on higher-risk areas, maximizing the value of limited audit capacity by focusing on where assurance is most needed." },
  { id:10420, domain:2, level:2, question:"What is a PRIMARY advantage of integrating risk management with the change management process?", options:["A It ensures risk implications of changes are assessed before implementation, preventing introduction of new unmanaged risks","B It removes the need for security testing","C It delegates risk decisions to change managers","D It slows down change implementations"], correct:0, explanation:"Integrating risk management with change management ensures that proposed changes are assessed for security risks before implementation, preventing new risks from being introduced unknowingly." },
  { id:10421, domain:2, level:3, question:"A risk manager is presenting to the board and is asked to explain why residual risk cannot be reduced to zero. What is the BEST response?", options:["A There is always some inherent uncertainty and some risks are economically impractical to fully eliminate; the goal is to keep risk within appetite","B Technology limitations prevent risk elimination","C Zero risk is a regulatory requirement that cannot be met","D Zero risk is achievable with sufficient investment"], correct:0, explanation:"Complete risk elimination is neither achievable (due to inherent uncertainty) nor economically rational; effective risk management aims to keep risk within appetite, not eliminate it entirely." },
  { id:10422, domain:2, level:3, question:"An organization's risk register shows 150 risks. Senior management asks how to prioritize treatment. What is the BEST approach?", options:["A Prioritize by combined risk rating, focusing first on risks above tolerance while accepting risks below appetite","B Randomly select 20 risks to address first","C Treat the most recently identified risks first","D Treat all 150 risks simultaneously"], correct:0, explanation:"Prioritizing by combined risk rating (likelihood × impact) ensures the most significant risks are addressed first, with clear triage between risks requiring treatment and those acceptable for acceptance." },
  { id:10423, domain:2, level:3, question:"What is the MOST important characteristic of a risk management program that supports organizational resilience?", options:["A A large team of risk analysts","B Annual risk assessments","C Continuous monitoring and rapid response capability that allows the organization to detect and adapt to risk changes in near real-time","D A comprehensive risk register"], correct:2, explanation:"Resilience requires continuous monitoring and rapid response capability; annual assessments alone cannot keep pace with rapidly evolving threats that organizational resilience must address." },
  { id:10424, domain:2, level:3, question:"When a new CISM practitioner joins an organization, what should be their FIRST priority in risk management?", options:["A Immediately revamp all risk management processes","B Commission an external risk assessment","C Implement new security controls","D Understand the current risk posture, existing risk management framework, and risk appetite before making changes"], correct:3, explanation:"Understanding the current state—risk posture, existing framework, and risk appetite—provides the foundation for informed, targeted improvements rather than disruptive, uninformed change." },
  { id:10425, domain:2, level:3, question:"An organization is considering entering a new market that significantly increases its risk profile. Who should have final authority to approve this strategic risk acceptance?", options:["A The board of directors or senior executive leadership","B The CISO","C The information security team","D The risk manager"], correct:0, explanation:"Strategic risk decisions that materially change the organization's risk profile require board or senior executive authority, as they affect organizational direction and stakeholder interests." },
  { id:10426, domain:2, level:1, question:"What is the purpose of 'risk scoring' in a risk assessment?", options:["A To assign a numerical or categorical value to a risk based on likelihood and impact, enabling consistent prioritization","B To eliminate subjectivity from risk ratings","C To assign risk to the responsible team","D To determine the cost of risk treatment"], correct:0, explanation:"Risk scoring assigns consistent ratings based on likelihood and impact, enabling comparable prioritization of risks across the organization regardless of who performs the assessment." },
  { id:10427, domain:2, level:1, question:"Which of the following BEST describes 'operational risk' in information security?", options:["A Risk from external hackers","B Risk arising from failures in internal processes, people, or systems","C Risk from regulatory non-compliance","D Risk from natural disasters only"], correct:1, explanation:"Operational risk encompasses failures in internal processes, human error, system failures, and inadequate controls that can result in security incidents or business disruption." },
  { id:10428, domain:2, level:1, question:"What is the FIRST step when responding to a newly identified high-rated risk?", options:["A Transfer the risk to insurers","B Assign a risk owner and begin impact/likelihood assessment to confirm the rating and determine treatment options","C Document the risk and wait for the next review cycle","D Immediately implement controls"], correct:1, explanation:"The first step is confirming the risk rating through proper assessment and assigning ownership, ensuring the risk is properly understood before treatment decisions are made." },
  { id:10429, domain:2, level:1, question:"Which of the following risk treatment options requires ongoing monitoring to verify the risk remains within acceptance criteria?", options:["A Risk acceptance","B Risk mitigation","C Risk transfer","D Risk avoidance"], correct:0, explanation:"Accepted risks must be continuously monitored to ensure they remain within the acceptance criteria, as changes in threat landscape or business context may make previously accepted risks unacceptable." },
  { id:10430, domain:2, level:1, question:"What type of risk analysis approach is BEST suited when historical data is unavailable?", options:["A Quantitative analysis","B Monte Carlo simulation","C Qualitative analysis","D FAIR analysis"], correct:2, explanation:"Qualitative analysis using expert judgment and relative scales is most practical when historical data is unavailable, providing meaningful risk ratings without requiring precise numerical inputs." },
  { id:10431, domain:2, level:2, question:"What is the MOST significant risk introduced by employees working remotely?", options:["A Reduced office space utilization","B Expanded attack surface through personal devices and home networks outside organizational security controls","C Increased IT support costs","D Decreased productivity"], correct:1, explanation:"Remote work expands the attack surface through unsecured home networks, personal devices, and increased reliance on VPNs, creating additional vectors beyond organizational security perimeters." },
  { id:10432, domain:2, level:2, question:"An organization finds that its risk assessment results are significantly different from those of peer organizations. What is the MOST likely cause?", options:["A The organization is being dishonest about its risks","B Peer organizations face different risks","C Peer organizations have better security controls","D Differences in risk assessment methodology, criteria, or scope rather than actual risk differences"], correct:3, explanation:"Differences in methodology, scoring criteria, scope, or assumptions commonly explain divergent results between organizations, not necessarily actual differences in risk levels." },
  { id:10433, domain:2, level:2, question:"What is the PRIMARY benefit of using risk scenarios derived from COBIT for risk identification?", options:["A They are legally required for compliance","B They provide a comprehensive, structured library of IT-related risk scenarios aligned to business objectives","C They replace the need for organization-specific assessments","D They are the most technically detailed scenarios available"], correct:1, explanation:"COBIT risk scenarios provide a structured, comprehensive library aligned to business objectives, offering a practical starting point for identifying IT risks without starting from scratch." },
  { id:10434, domain:2, level:2, question:"Which of the following BEST describes 'inherent risk' in a process that lacks any security controls?", options:["A It cannot be assessed without control data","B It is always acceptable","C It represents the risk after all controls are applied","D It represents the raw risk level before any controls are in place"], correct:3, explanation:"Inherent risk is the raw risk level that would exist in the absence of any controls; understanding it helps assess how much risk reduction existing controls provide." },
  { id:10435, domain:2, level:2, question:"What is the BEST way to ensure risk management decisions are consistent across an organization?", options:["A Allow each department to develop its own approach","B Have all decisions made by a single person","C Use a standardized risk framework with consistent criteria, scales, and approval processes applied organization-wide","D Use external consultants for all decisions"], correct:2, explanation:"A standardized framework with common criteria, scales, and processes ensures comparability and consistency in risk decisions across departments and business units." },
  { id:10436, domain:2, level:3, question:"A CISM practitioner is reviewing the effectiveness of a third-party risk program. Which finding would be MOST concerning?", options:["A Some low-risk vendors were not assessed this year","B A critical vendor with access to sensitive data has never been formally assessed for security risks","C Vendor contracts were signed three years ago","D Some vendor assessments are overdue by two weeks"], correct:1, explanation:"An unassessed critical vendor with sensitive data access represents a significant governance failure; this is the highest-priority finding requiring immediate remediation in a third-party risk program." },
  { id:10437, domain:2, level:3, question:"An organization is planning a major system migration. What risk management activity is MOST critical during the migration period?", options:["A Suspend risk monitoring until migration is complete","B Increase risk monitoring frequency and implement additional controls to manage elevated transitional risks","C Accept all migration risks without documentation","D Postpone the risk register update until after migration"], correct:1, explanation:"Migration periods introduce elevated risk due to parallel systems, data conversions, and configuration changes; increased monitoring and additional controls are essential during this high-risk transition." },
  { id:10438, domain:2, level:3, question:"What is the MOST important factor when selecting a risk management software platform?", options:["A The platform's user interface design","B The vendor's market share","C Alignment with the organization's risk framework, ability to support risk workflows, and integration with existing systems","D The number of pre-built risk templates"], correct:2, explanation:"The platform must support the organization's specific risk framework and workflows, and integrate with existing systems to be effective; features and market share are secondary considerations." },
  { id:10439, domain:2, level:3, question:"How should a CISM practitioner address a situation where risk appetite is defined at the corporate level but not translated into operational guidance for business units?", options:["A Develop risk tolerance guidelines that translate corporate risk appetite into operational thresholds for each business unit","B Ignore the gap if no incidents have occurred","C Wait for the board to provide operational guidance","D Require each business unit to define its own risk appetite"], correct:0, explanation:"Translating corporate risk appetite into operational risk tolerance guidelines for business units bridges the gap between strategic policy and daily risk decisions, ensuring consistent application." },
  { id:10440, domain:2, level:3, question:"A CISM practitioner is asked to design a continuous risk monitoring program. Which capability is MOST essential for the program to be effective?", options:["A Annual external risk assessments","B Automated data collection tied to defined KRIs with threshold alerts and escalation workflows","C A large team of risk analysts reviewing dashboards daily","D The ability to generate weekly reports"], correct:1, explanation:"Automated KRI data collection with threshold alerts and escalation workflows enables proactive, continuous risk monitoring that responds to changes in real-time rather than relying on periodic manual review." }
];
if (typeof window !== 'undefined') window.QUESTIONS_CISM_C2 = QUESTIONS_CISM_C2;
